import{_ as l,o as e,c as i,a0 as t}from"./chunks/framework.CWk8AOcY.js";const b=JSON.parse('{"title":"什么是文件系统、镜像与可写层","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/concepts/filesystem-image-writable-layer.md","filePath":"zh/guide/concepts/filesystem-image-writable-layer.md"}'),o={name:"zh/guide/concepts/filesystem-image-writable-layer.md"};function r(h,a,n,p,s,d){return e(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="什么是文件系统、镜像与可写层" tabindex="-1">什么是文件系统、镜像与可写层 <a class="header-anchor" href="#什么是文件系统、镜像与可写层" aria-label="Permalink to &quot;什么是文件系统、镜像与可写层&quot;">​</a></h1><h2 id="一句话定义" tabindex="-1">一句话定义 <a class="header-anchor" href="#一句话定义" aria-label="Permalink to &quot;一句话定义&quot;">​</a></h2><p>在 CubeSandbox 里，环境的“文件世界”不是一个单层概念，而是至少由四层抽象构成：</p><ul><li><strong>镜像（Image）</strong>：环境输入</li><li><strong>根文件系统（Root Filesystem / rootfs）</strong>：运行基础内容</li><li><strong>Template</strong>：可发布母版</li><li><strong>可写层（Writable Layer）</strong>：实例级差异状态</li></ul><p>很多对 CubeSandbox 的误解，都来自把这四层混成“同一个东西”。</p><h2 id="为什么必须把文件系统概念分层" tabindex="-1">为什么必须把文件系统概念分层 <a class="header-anchor" href="#为什么必须把文件系统概念分层" aria-label="Permalink to &quot;为什么必须把文件系统概念分层&quot;">​</a></h2><p>如果不分层，你会很难回答这些问题：</p><ul><li>为什么可以从 OCI 镜像制作 Template？</li><li>为什么两个 Sandbox 能共享基础环境，却不能共享彼此运行中的文件改动？</li><li>为什么模板制作和实例创建是两个阶段？</li><li>为什么实例既像“从模板复制出来”，又还能拥有自己的独立文件状态？</li></ul><p>这些问题的答案都指向同一个事实：</p><blockquote><p><strong>CubeSandbox 不是把“一个镜像直接跑起来”，而是在管理一个分层环境系统。</strong></p></blockquote><h2 id="什么是镜像-image" tabindex="-1">什么是镜像（Image） <a class="header-anchor" href="#什么是镜像-image" aria-label="Permalink to &quot;什么是镜像（Image）&quot;">​</a></h2><h3 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h3><p>镜像是构建环境的输入材料。</p><p>它通常描述：</p><ul><li>需要哪些文件</li><li>需要哪些依赖</li><li>初始目录结构是什么</li><li>基础用户态环境如何组成</li></ul><h3 id="在-cubesandbox-中的角色" tabindex="-1">在 CubeSandbox 中的角色 <a class="header-anchor" href="#在-cubesandbox-中的角色" aria-label="Permalink to &quot;在 CubeSandbox 中的角色&quot;">​</a></h3><p>CubeSandbox 常常从 OCI 镜像开始构建环境，但镜像本身不是最终交付对象。</p><p>更准确地说，镜像回答的是：</p><blockquote><p>“这个环境的静态内容从哪里来？”</p></blockquote><p>而不是：</p><blockquote><p>“这个环境如何被高性能、强隔离地交付给用户？”</p></blockquote><h3 id="为什么镜像不是平台概念终点" tabindex="-1">为什么镜像不是平台概念终点 <a class="header-anchor" href="#为什么镜像不是平台概念终点" aria-label="Permalink to &quot;为什么镜像不是平台概念终点&quot;">​</a></h3><p>镜像非常重要，但它还不具备：</p><ul><li>Guest 运行状态</li><li>平台探针语义</li><li>可复用快照状态</li><li>统一发布对象身份</li></ul><p>所以镜像只是起点。</p><h2 id="什么是根文件系统-rootfs" tabindex="-1">什么是根文件系统（rootfs） <a class="header-anchor" href="#什么是根文件系统-rootfs" aria-label="Permalink to &quot;什么是根文件系统（rootfs）&quot;">​</a></h2><h3 id="定义-1" tabindex="-1">定义 <a class="header-anchor" href="#定义-1" aria-label="Permalink to &quot;定义&quot;">​</a></h3><p>根文件系统是实例或模板在 Guest 内部看到的基础文件内容集合。</p><p>它比“镜像”更接近实际运行环境，因为它已经是一个可被运行时使用的文件系统基础。</p><h3 id="它解决什么问题" tabindex="-1">它解决什么问题 <a class="header-anchor" href="#它解决什么问题" aria-label="Permalink to &quot;它解决什么问题&quot;">​</a></h3><p>镜像往往是分发格式；rootfs 更接近运行格式。</p><p>换句话说：</p><ul><li>镜像描述怎么分发环境</li><li>rootfs 描述实例启动时到底能看到哪些文件</li></ul><h3 id="为什么-rootfs-不是完整环境" tabindex="-1">为什么 rootfs 不是完整环境 <a class="header-anchor" href="#为什么-rootfs-不是完整环境" aria-label="Permalink to &quot;为什么 rootfs 不是完整环境&quot;">​</a></h3><p>即便有了 rootfs，也不等于已经有完整 Sandbox。</p><p>因为一个完整环境还需要：</p><ul><li>Guest 内核</li><li>运行时状态</li><li>网络配置</li><li>实例元数据</li><li>可写层与生命周期状态</li></ul><p>所以 rootfs 是环境基础，但不是环境全貌。</p><h2 id="什么是-template-在文件系统层面的意义" tabindex="-1">什么是 Template 在文件系统层面的意义 <a class="header-anchor" href="#什么是-template-在文件系统层面的意义" aria-label="Permalink to &quot;什么是 Template 在文件系统层面的意义&quot;">​</a></h2><p>Template 可以理解成“以 rootfs 为基础，再叠加可复用运行准备结果后的平台母版”。</p><p>从文件系统视角看，它至少意味着两件事：</p><ol><li>基础环境已经被整理成可复用母版</li><li>后续实例创建时可以共享这份基础，而不必重新构造整套环境</li></ol><p>所以 Template 不是简单“另一个文件系统格式”，而是把文件系统基础、运行状态和平台元数据组织成一个可发布对象。</p><h2 id="什么是可写层-writable-layer" tabindex="-1">什么是可写层（Writable Layer） <a class="header-anchor" href="#什么是可写层-writable-layer" aria-label="Permalink to &quot;什么是可写层（Writable Layer）&quot;">​</a></h2><h3 id="定义-2" tabindex="-1">定义 <a class="header-anchor" href="#定义-2" aria-label="Permalink to &quot;定义&quot;">​</a></h3><p>可写层是 Sandbox 实例级的可变文件状态。</p><p>它承载的是这个实例在运行过程中发生的文件系统差异，例如：</p><ul><li>新建文件</li><li>修改配置</li><li>下载依赖</li><li>写入工作目录</li><li>生成临时结果</li></ul><h3 id="为什么它必须是实例级的" tabindex="-1">为什么它必须是实例级的 <a class="header-anchor" href="#为什么它必须是实例级的" aria-label="Permalink to &quot;为什么它必须是实例级的&quot;">​</a></h3><p>如果多个 Sandbox 直接共享可写状态，会立即出现问题：</p><ul><li>一个实例改文件会污染另一个实例</li><li>同一模板无法稳定复用</li><li>实例间缺乏边界</li><li>回收与问题定位会极其困难</li></ul><p>因此 CubeSandbox 必须做到：</p><blockquote><p><strong>共享基础，不共享差异。</strong></p></blockquote><p>可写层就是这个“差异层”。</p><h2 id="最核心的分层关系" tabindex="-1">最核心的分层关系 <a class="header-anchor" href="#最核心的分层关系" aria-label="Permalink to &quot;最核心的分层关系&quot;">​</a></h2><p>你可以把这四层关系记成一句话：</p><ul><li>镜像提供原材料</li><li>rootfs 提供运行基础</li><li>Template 提供可复用母版</li><li>可写层提供实例差异</li></ul><p>这是理解 CubeSandbox 文件系统模型最重要的主线。</p><h2 id="为什么这套分层对性能和密度很关键" tabindex="-1">为什么这套分层对性能和密度很关键 <a class="header-anchor" href="#为什么这套分层对性能和密度很关键" aria-label="Permalink to &quot;为什么这套分层对性能和密度很关键&quot;">​</a></h2><p>CubeSandbox 的目标不是让每个实例都拥有一份完全独立、从零复制的完整环境，而是：</p><ul><li>尽可能共享基础层</li><li>尽可能把差异限制在实例级可写层</li><li>在安全边界成立的前提下最大化复用</li></ul><p>这会直接影响两个关键指标：</p><h3 id="_1-存储效率" tabindex="-1">1. 存储效率 <a class="header-anchor" href="#_1-存储效率" aria-label="Permalink to &quot;1. 存储效率&quot;">​</a></h3><p>共享基础意味着不必为每个实例复制整套环境内容。</p><h3 id="_2-内存和启动效率" tabindex="-1">2. 内存和启动效率 <a class="header-anchor" href="#_2-内存和启动效率" aria-label="Permalink to &quot;2. 内存和启动效率&quot;">​</a></h3><p>当系统在文件系统和运行状态上都能良好分层时，实例创建就更接近“挂载差异层并恢复状态”，而不是“现场拼装新系统”。</p><h2 id="为什么-镜像-模板-实例-是三段而不是一步" tabindex="-1">为什么“镜像 -&gt; 模板 -&gt; 实例”是三段而不是一步 <a class="header-anchor" href="#为什么-镜像-模板-实例-是三段而不是一步" aria-label="Permalink to &quot;为什么“镜像 -&gt; 模板 -&gt; 实例”是三段而不是一步&quot;">​</a></h2><p>这是 CubeSandbox 设计最值得理解的一点。</p><h3 id="第一步-镜像到基础环境" tabindex="-1">第一步：镜像到基础环境 <a class="header-anchor" href="#第一步-镜像到基础环境" aria-label="Permalink to &quot;第一步：镜像到基础环境&quot;">​</a></h3><p>系统先从镜像得到基础内容。</p><h3 id="第二步-基础环境到模板" tabindex="-1">第二步：基础环境到模板 <a class="header-anchor" href="#第二步-基础环境到模板" aria-label="Permalink to &quot;第二步：基础环境到模板&quot;">​</a></h3><p>系统再把基础内容预热、固化、组织成可复用 Template。</p><h3 id="第三步-模板到实例" tabindex="-1">第三步：模板到实例 <a class="header-anchor" href="#第三步-模板到实例" aria-label="Permalink to &quot;第三步：模板到实例&quot;">​</a></h3><p>系统最后在共享基础之上，为每个 Sandbox 附加自己的实例差异状态。</p><p>这三步分别解决：</p><ul><li>输入来源</li><li>母版复用</li><li>实例个体化</li></ul><p>如果把它们压成一步，系统很难同时获得高性能、高密度与高可治理性。</p><h2 id="为什么文件系统概念和快照概念紧密相连" tabindex="-1">为什么文件系统概念和快照概念紧密相连 <a class="header-anchor" href="#为什么文件系统概念和快照概念紧密相连" aria-label="Permalink to &quot;为什么文件系统概念和快照概念紧密相连&quot;">​</a></h2><p>文件系统分层主要解决“静态和实例差异怎么组织”； 快照机制主要解决“运行状态怎么复用”。</p><p>两者合在一起，才形成完整的极速交付模型：</p><ul><li>文件系统共享基础</li><li>可写层承接差异</li><li>Snapshot 复用运行准备状态</li></ul><p>所以当你听到“热启动很快”，不要只想到内存快照，也要想到背后的文件系统分层。</p><h2 id="为什么文件系统概念和安全概念也有关系" tabindex="-1">为什么文件系统概念和安全概念也有关系 <a class="header-anchor" href="#为什么文件系统概念和安全概念也有关系" aria-label="Permalink to &quot;为什么文件系统概念和安全概念也有关系&quot;">​</a></h2><p>文件系统不仅关乎性能，还关乎边界。</p><p>例如：</p><ul><li>实例是否能看到其它实例的状态</li><li>实例修改是否会污染母版</li><li>回收后差异状态是否被正确清理</li><li>Guest 内文件视图是否严格限制在实例边界内</li></ul><p>所以“分层文件系统”不仅是资源优化问题，也是隔离与治理问题。</p><h2 id="常见误解" tabindex="-1">常见误解 <a class="header-anchor" href="#常见误解" aria-label="Permalink to &quot;常见误解&quot;">​</a></h2><h3 id="误解一-template-就是一份-rootfs-归档" tabindex="-1">误解一：Template 就是一份 rootfs 归档 <a class="header-anchor" href="#误解一-template-就是一份-rootfs-归档" aria-label="Permalink to &quot;误解一：Template 就是一份 rootfs 归档&quot;">​</a></h3><p>不对。</p><p>rootfs 是文件基础；Template 是平台母版对象，往往还包含运行状态与发布语义。</p><h3 id="误解二-镜像和模板只是名字不同" tabindex="-1">误解二：镜像和模板只是名字不同 <a class="header-anchor" href="#误解二-镜像和模板只是名字不同" aria-label="Permalink to &quot;误解二：镜像和模板只是名字不同&quot;">​</a></h3><p>不对。</p><p>镜像偏输入分发；模板偏平台复用与交付。</p><h3 id="误解三-可写层只是一个小优化" tabindex="-1">误解三：可写层只是一个小优化 <a class="header-anchor" href="#误解三-可写层只是一个小优化" aria-label="Permalink to &quot;误解三：可写层只是一个小优化&quot;">​</a></h3><p>不对。</p><p>可写层是实例差异边界得以成立的核心抽象之一。如果没有它，模板复用和实例隔离都会变得混乱。</p><h2 id="运维和平台设计最该关心什么" tabindex="-1">运维和平台设计最该关心什么 <a class="header-anchor" href="#运维和平台设计最该关心什么" aria-label="Permalink to &quot;运维和平台设计最该关心什么&quot;">​</a></h2><p>你在实际工作中最应该关注这四个判断：</p><ol><li><strong>哪些层是共享基础，哪些层是实例差异。</strong></li><li><strong>镜像、模板、rootfs 的职责是否被混用。</strong></li><li><strong>实例回收是否真正清理了可写层状态。</strong></li><li><strong>环境变更到底应该落在镜像、模板还是实例层。</strong></li></ol><h2 id="和相关文档的关系" tabindex="-1">和相关文档的关系 <a class="header-anchor" href="#和相关文档的关系" aria-label="Permalink to &quot;和相关文档的关系&quot;">​</a></h2><ul><li>想看 Template 作为母版对象： <a href="./template.html">什么是 Template</a></li><li>想看热启动能力： <a href="./snapshot-hotstart.html">什么是 Snapshot、冷启动与热启动</a></li><li>想看模板制作命令： <a href="./../tutorials/template-from-image.html">从 OCI 镜像制作模板</a></li><li>想看运维侧存储与目录： <a href="./../ops-manual/04-install-layout-and-generated-files.html">安装目录、生成文件与落盘路径</a></li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>理解了环境内容和状态如何分层之后，最后一个必须讲透的概念就是：</p><p><strong>CubeSandbox 到底隔离了什么、没隔离什么，它的安全边界到底在哪里？</strong></p><p>下一章专门回答这个问题： <a href="./security-boundary.html">什么是安全边界与隔离模型</a>。</p>',106)])])}const c=l(o,[["render",r]]);export{b as __pageData,c as default};
